#include<bits/stdc++.h>
using namespace std;
int num[12],len;
long long l,r,dp[11][11][11][2][2][2][2];
long long dfs(int p,int a,int b,bool c,bool d,bool flag4,bool flag8)
{
    if(flag4&&flag8)
    {
        return 0;
    }
    if(p<=0)
    {
        return c;
    }
    if(dp[p][a][b][c][d][flag4][flag8]!=-1)
    {
        return dp[p][a][b][c][d][flag4][flag8];
    }
    long long ans=0;
    int lim=(d==0?num[p]:9);
    for(int i=0;i<=lim;i++)
    {
        ans+=dfs(p-1,i,a,c||(i==b&&i==a),d||(i<lim),flag4||(i==4),flag8||(i==8));
    }
    return dp[p][a][b][c][d][flag4][flag8]=ans;
}
long long calc(long long x)
{
    if(x<1e10)
    {
        return 0;
    }
    memset(dp,-1,sizeof(dp));
    len=0;
    while(x)
    {
        num[++len]=x%10;
        x/=10;
    }
    long long ans=0;
    for(int i=1;i<=num[len];i++)
    {
        ans+=dfs(10,i,0,0,i<num[len],i==4,i==8);
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&l,&r);
    printf("%lld",calc(r)-calc(l-1));
    return 0;
}
